// Obtener el valor original del campo
const sender = $('If4').first().json.telefono;
// Eliminar el prefijo '34' o '49' si existe, y quitar el dominio de WhatsApp
const cleanedNumber = sender
  .replace(/^(\+?34|\+?49)/, '')       // Quita el '+34', '34', '+49' o '49' al inicio
  .replace(/@s\.whatsapp\.net$/, ''); // Quita el '@s.whatsapp.net' al final

// Devolver el número limpio
return [
  {
    json: {
      cleanedNumber
    }
  }
];

const respuesta = $input.first().json.output;

const partes = respuesta
  .split(/\\n\\n|\n\n/)
  .map(p => p.replace(/\\n|\n/g, ' ').trim())
  .filter(p => p.length > 0);

const result = {};
partes.forEach((p, i) => {
  result[`parte_${i + 1}`] = p;
});

return [{ json: result }];

